UPDATE cliptracker_v2_questions SET options = '["Monday is when managers roll up forecasts and present a written summary to VPs — the AE''s most critical day is Wednesday when they report pipeline status to their VP directly", "Monday is when AEs update all open opportunities — the most critical day for AEs is Tuesday, when managers run forecast calls to review pipeline accuracy and deal health", "Monday is when AEs submit their written commit call to their manager in Outreach — the most critical day is Friday when Nate presents the final number to Thomas", "Monday is reserved for deal work — the most critical day is Thursday when VPs present to Nate and AEs must have all deal updates locked before that conversation happens"]' WHERE id = '97fc85f5-1421-4a40-be4d-4ae0e89c0c36';

