-- Q4 (first_pass, sort=4, correct=1) — MAJOR compress correct; inflate wrongs
UPDATE cliptracker_v2_questions SET options = '["Stakeholder turnover — when a champion or economic buyer leaves an account, renewal probability drops sharply regardless of utilization level or payment history and requires an immediate recovery plan", "Volume utilization — below 50% is massive churn risk, below 60% is still high, and 70% and above is where things start to look healthier", "Payment delinquency — customers 30 or more days past due on an invoice signal churn risk more reliably than product usage, especially on multi-year contracts approaching renewal", "Gainsight product health score — a red health score is the single most reliable churn indicator and overrides all other signals including utilization numbers and payment status"]' WHERE id = '925e4f60-d59e-4e5b-9d8c-c54f0129b7dd';

-- Q5 (first_pass, sort=5, correct=1) — compress correct; inflate wrongs
