UPDATE cliptracker_v2_questions SET options = '["It means maintaining backup deals at S2 ready to swap in if a primary deal slips — Amplitude expects AEs to build a shadow pipeline specifically to buffer against this scenario", "It means structuring your forecast so multiple different deal combinations can each get you to the same number — you don''t need to know which deals close, just that enough of them will", "It means submitting a best case and worst case alongside your commit so leadership has a full range of possible outcomes before presenting to the street", "It means building pipeline across multiple verticals so a single industry downturn can''t single-handedly derail your quarterly number"]' WHERE id = '20e796eb-3445-4051-9993-e84613cdca79';

-- S&R Q2 (recovery, sort=2, correct=1) — compress correct; inflate wrongs
UPDATE cliptracker_v2_questions SET options = '["Champion, economic buyer, MEDDIC scorecard, and mutual action plan — the deal quality indicators leadership inspects on every weekly forecast call", "Next steps, close date, stage, forecast category, and new ARR — update these immediately when anything changes, not held until the following Monday", "Outreach sequence status, last contact date, executive sponsor, and AE rollup — these power the automated forecast submission feeding into the VP review", "Renewal commit, churn deal rollup, pipeline coverage ratio, and Gainsight health score — the renewal-specific fields Corey monitors every week"]' WHERE id = '1544b2db-7555-4c6b-85bf-1c4ea593b4e3';

-- S&R Q3 (recovery, sort=3, correct=1) — compress correct; inflate wrongs
UPDATE cliptracker_v2_questions SET options = '["New business tracks net new logos only — renewals cover both upsells and downsells on existing accounts regardless of whether a new product line is being added", "New business answers how much net new ARR you will land or expand this quarter — the renewal forecast is the inverse, tracking ARR you expect to lose from churn", "New business is submitted weekly covering only the current quarter — renewals are submitted monthly and span both the current and following quarter simultaneously", "New business has three forecast calls (worst case, commit, best case) — renewals use a single net retention rate rather than explicit dollar commit and churn calls"]' WHERE id = '147db2e6-6f13-4680-9f5e-2cdb736ceb1b';

-- S&R Q4 (recovery, sort=4, correct=1) — MAJOR compress correct; inflate wrongs
UPDATE cliptracker_v2_questions SET options = '["Ask what this deal is worth to Amplitude — framing it in terms of strategic impact rather than ARR alone helps prioritize which opportunities deserve the most active attention this week", "Ask not why this deal will close but why it would not — this risk frame is exactly how leadership reviews forecasts, and it forces you to identify and mitigate real threats before they materialize", "Ask what the customer would say if you called them right now — keeping the forecast grounded in buyer perspective ensures it reflects actual momentum rather than internal assumptions", "Ask what minimum amount from this deal still hits your number — anchoring on minimum viable outcomes tightens accuracy and prevents overcommitment to deals still in mid-cycle"]' WHERE id = '11d27694-2ed4-462a-bd91-1823e6c48a7c';

-- S&R Q5 (recovery, sort=5, correct=0) — MAJOR compress correct; inflate wrongs
