UPDATE cliptracker_v2_questions SET options = '["Hook, context, social proof, and a clear call to action — four elements that work together to move the prospect toward committing to a defined next step", "Introduction (hero''s current situation), conflict (the crisis that forces action), turning point (where the hero acts to resolve it), and the end (the outcome showing growth or success)", "Problem statement, solution overview, quantified results, and a closing recommendation — four parts that map cleanly to the prospect''s decision journey from awareness to commitment", "Discovery phase, challenge acknowledgment, resolution through the product, and a closing recommendation — four phases mirroring how a discovery call naturally progresses from pain to solution"]' WHERE id = 'ad68d7f9-1cea-4a44-9eb0-e48336d1664f';

-- Q7 (first_pass, sort=7, correct=1) — compress correct; inflate wrongs
UPDATE cliptracker_v2_questions SET options = '["Personal means drawing from your own experience as a seller — stories from your prior deals and companies are more relatable to prospects than any third-party case study", "The story is about the people, not the technology — the customer is the hero because prospects empathize with people, not tools. Amplitude is the Millennium Falcon, not Han Solo.", "Personal means the story is tailored to the specific industry of the prospect — vertical industry alignment is what creates the feeling of personal relevance in any customer narrative", "Personal means sharing the story in a one-on-one setting rather than a group — the intimacy of delivery is what makes a customer story feel genuinely personal to the listener"]' WHERE id = 'a2d00822-f463-434f-bd74-56856eab6c20';

